        //                 "symbol": "BTC",
        //                 "amount": "0.1",
        //                 "status": "completed",
        //                 "createdAt": "1700000000000"
        //             }
        //         ],
        //         "start": 0,
        //         "end": 0,
        //         "limit": 25
        //     }
        //
        object items = this.safeList(response, "items", new List<object>() {});
        return this.parseTransfers(items, currency, since, limit);
    }

