    public virtual object parseLedgerEntryType(object type)
    {
        object types = new Dictionary<string, object>() {
            { "buy", "trade" },
            { "sell", "trade" },
            { "deposit", "transaction" },
            { "withdrawal", "transaction" },
            { "withdrawal_cancelled", "transaction" },
